import { InjectQueue } from '@nestjs/bullmq';
import { Injectable, Logger } from '@nestjs/common';
import { Queue } from 'bullmq';

import { JiraChangelogModel } from '@modules/jira/db/jira-changelog.model';
import { JiraInstallationModel } from '@modules/jira/db/jira-installations.model';
import { JiraIssueModel } from '@modules/jira/db/jira-issues.model';
import { JiraProjectModel } from '@modules/jira/db/jira-projects.model';
import { JiraSprintModel } from '@modules/jira/db/jira-sprints.model';
import { JiraWorklogModel } from '@modules/jira/db/jira-worklogs.model';
import { JiraApiService } from '@modules/jira/jira-api.service';
import { IJiraApiIssue } from '@modules/jira/types/jira-api.interface';
import { IJiraIssueBase } from '@modules/jira/types/jira-installation.interface';

const THREE_YEARS_MS = 3 * 365 * 24 * 60 * 60 * 1000;

@Injectable()
export class JiraSyncService {
	private readonly logger = new Logger(JiraSyncService.name);

	constructor(
		private readonly installationModel: JiraInstallationModel,
		private readonly projectModel: JiraProjectModel,
		private readonly issueModel: JiraIssueModel,
		private readonly changelogModel: JiraChangelogModel,
		private readonly worklogModel: JiraWorklogModel,
		private readonly sprintModel: JiraSprintModel,
		private readonly jiraApiService: JiraApiService,
		@InjectQueue('jira') private readonly jiraQueue: Queue,
	) {}

	async discoverProjects({ installationDbId }: { installationDbId: string }): Promise<void> {
		const installation = await this.installationModel.findById({ id: installationDbId });

		if (!installation) {
			this.logger.warn(`Installation ${installationDbId} not found`);
			return;
		}

		const token = await this.jiraApiService.getValidToken({ installation });
		const projects = await this.jiraApiService.listProjects({
			cloudId: installation.cloud_id,
			token,
		});

		await this.projectModel.upsertMany({ installationId: installationDbId, projects });

		const savedProjects = await this.projectModel.findByInstallationId({
			installationId: installationDbId,
		});

		for (const project of savedProjects) {
			await this.jiraQueue.add(
				'sync_project',
				{
					installationDbId,
					projectDbId: project._id,
					projectKey: project.project_key,
					projectId: project.project_id,
				},
				{ attempts: 3, backoff: { type: 'exponential', delay: 5000 } },
			);
		}

		this.logger.debug(
			`Enqueued sync for ${savedProjects.length} projects in installation ${installationDbId}`,
		);
	}

	async syncProject({
		installationDbId,
		projectDbId,
		projectKey,
	}: {
		installationDbId: string;
		projectDbId: string;
		projectKey: string;
	}): Promise<void> {
		const installation = await this.installationModel.findById({ id: installationDbId });

		if (!installation) {
			this.logger.warn(`Installation ${installationDbId} not found`);
			return;
		}

		const projects = await this.projectModel.findByInstallationId({
			installationId: installationDbId,
		});
		const project = projects.find((p) => p._id === projectDbId);

		if (!project) {
			this.logger.warn(`Project ${projectDbId} not found`);
			return;
		}

		const token = await this.jiraApiService.getValidToken({ installation });

		const since = project.last_synced_at
			? project.last_synced_at
			: new Date(Date.now() - THREE_YEARS_MS);

		const sinceStr = since.toISOString().split('T')[0] ?? since.toISOString();
		const jql = `project = "${projectKey}" AND updated >= "${sinceStr}" ORDER BY updated ASC`;

		await this.fetchAndStoreIssues({
			installationDbId,
			projectDbId,
			cloudId: installation.cloud_id,
			token,
			jql,
		});

		await this.fetchAndStoreSprints({
			installationDbId,
			projectKey,
			cloudId: installation.cloud_id,
			token,
		});

		await this.projectModel.updateLastSyncedAt({ id: projectDbId });

		this.logger.debug(`Sync complete for project ${projectKey} in installation ${installationDbId}`);
	}

	async pollAllInstallations(): Promise<void> {
		const installations = await this.installationModel.findAllActive();

		for (const installation of installations) {
			await this.jiraQueue.add(
				'discover_projects',
				{ installationDbId: installation._id },
				{ attempts: 3, backoff: { type: 'exponential', delay: 5000 } },
			);
		}

		this.logger.debug(`Triggered discover_projects for ${installations.length} active installations`);
	}

	private async fetchAndStoreIssues({
		installationDbId,
		projectDbId,
		cloudId,
		token,
		jql,
	}: {
		installationDbId: string;
		projectDbId: string;
		cloudId: string;
		token: string;
		jql: string;
	}): Promise<void> {
		let startAt = 0;
		const pageSize = 100;

		while (true) {
			const response = await this.jiraApiService.searchIssues({
				cloudId,
				token,
				jql,
				startAt,
			});

			if (response.issues.length === 0) break;

			const savedIssues = await this.issueModel.upsertMany({
				issues: response.issues.map((issue) => ({
					installation_id: installationDbId,
					project_id: projectDbId,
					issue_key: issue.key,
					issue_id: issue.id,
					issue_type: issue.fields.issuetype?.name ?? null,
					status: issue.fields.status?.name ?? null,
					priority: issue.fields.priority?.name ?? null,
					assignee_id: issue.fields.assignee?.accountId ?? null,
					reporter_id: issue.fields.reporter?.accountId ?? null,
					story_points: issue.fields.customfield_10016 ?? null,
					updated_at: new Date(issue.fields.updated),
					resolved_at: issue.fields.resolutiondate
						? new Date(issue.fields.resolutiondate)
						: null,
				})),
			});

			await this.storeChangelogs({
				installationDbId,
				issues: response.issues,
				savedIssues,
			});

			await this.storeWorklogs({
				installationDbId,
				cloudId,
				token,
				issues: response.issues,
				savedIssues,
			});

			startAt += pageSize;
			if (startAt >= response.total || response.issues.length < pageSize) break;
		}
	}

	private async storeChangelogs({
		installationDbId,
		issues,
		savedIssues,
	}: {
		installationDbId: string;
		issues: IJiraApiIssue[];
		savedIssues: IJiraIssueBase[];
	}): Promise<void> {
		const issueDbIdMap = new Map(savedIssues.map((i) => [i.issue_id, i._id]));
		const entries = [];

		for (const issue of issues) {
			const issueDbId = issueDbIdMap.get(issue.id);
			if (!issueDbId || !issue.changelog) continue;

			for (const history of issue.changelog.histories) {
				for (const item of history.items) {
					entries.push({
						issue_id: issueDbId,
						installation_id: installationDbId,
						jira_history_id: history.id,
						author_id: history.author?.accountId ?? null,
						field: item.field,
						from_value: item.fromString,
						to_value: item.toString,
						changed_at: new Date(history.created),
					});
				}
			}
		}

		await this.changelogModel.upsertMany({ entries });
	}

	private async storeWorklogs({
		installationDbId,
		cloudId,
		token,
		issues,
		savedIssues,
	}: {
		installationDbId: string;
		cloudId: string;
		token: string;
		issues: IJiraApiIssue[];
		savedIssues: IJiraIssueBase[];
	}): Promise<void> {
		const issueDbIdMap = new Map(savedIssues.map((i) => [i.issue_id, i._id]));

		for (const issue of issues) {
			const issueDbId = issueDbIdMap.get(issue.id);
			if (!issueDbId) continue;

			const worklogs = await this.jiraApiService.getWorklogsForIssue({
				cloudId,
				token,
				issueId: issue.id,
			});

			if (worklogs.length === 0) continue;

			await this.worklogModel.upsertMany({
				worklogs: worklogs.map((w) => ({
					issue_id: issueDbId,
					installation_id: installationDbId,
					jira_worklog_id: w.id,
					author_id: w.author?.accountId ?? null,
					time_spent_sec: w.timeSpentSeconds,
					started_at: w.started ? new Date(w.started) : null,
					updated_at: new Date(w.updated),
				})),
			});
		}
	}

	private async fetchAndStoreSprints({
		installationDbId,
		projectKey,
		cloudId,
		token,
	}: {
		installationDbId: string;
		projectKey: string;
		cloudId: string;
		token: string;
	}): Promise<void> {
		try {
			const boardsResponse = await this.jiraApiService.listBoards({
				cloudId,
				token,
				projectKeyOrId: projectKey,
			});

			for (const board of boardsResponse.values) {
				let startAt = 0;
				while (true) {
					const sprintResponse = await this.jiraApiService.listSprints({
						cloudId,
						token,
						boardId: board.id,
						startAt,
					});

					await this.sprintModel.upsertMany({
						installationId: installationDbId,
						boardId: String(board.id),
						sprints: sprintResponse.values,
					});

					if (sprintResponse.isLast || sprintResponse.values.length === 0) break;
					startAt += 50;
				}
			}
		} catch (error) {
			this.logger.warn(
				`Failed to fetch sprints for project ${projectKey}: ${(error as Error).message}`,
			);
		}
	}
}
